```class Solution {
    public int[] popcountDepth(long[] nums, long[][] queries) {
        int n = nums.length;
        int[] res = new int[queries.length];
        for (int i = 0; i < queries.length; i++) {
            if (queries[i][0] == 1) {
                int count = 0;
                for (int j = queries[i][1]; j <= queries[i][2]; j++) {
                    long num = nums[j];
                    int depth = 0;
                    while ((num & 1) == 0) {
                        num >>= 1;
                        depth++;
                    }
                    if (depth == queries[i][3]) {
                        count++;
                    }
                }
                res[i] = count;
            } else {
                nums[queries[i][1]] = queries[i][2];
            }
        }
        return res;
    }
}```
